我将为您实现两种线程安全的单例模式，并详细说明其原理。

## 方法一：使用 std::call_once（推荐）

```cpp
#include <iostream>
#include <mutex>
#include <thread>
#include <vector>
#include <memory>

class ThreadSafeSingleton {
private:
    static std::unique_ptr<ThreadSafeSingleton> instance_;
    static std::once_flag once_flag_;

    // 私有构造函数，防止外部创建实例
    ThreadSafeSingleton() {
        std::cout << "ThreadSafeSingleton constructed in thread: " 
                  << std::this_thread::get_id() << std::endl;
    }

public:
    // 禁止拷贝构造和赋值操作
    ThreadSafeSingleton(const ThreadSafeSingleton&) = delete;
    ThreadSafeSingleton& operator=(const ThreadSafeSingleton&) = delete;

    // 获取单例实例
    static ThreadSafeSingleton* getInstance() {
        std::call_once(once_flag_, []() {
            instance_ = std::unique_ptr<ThreadSafeSingleton>(new ThreadSafeSingleton());
        });
        return instance_.get();
    }

    // 业务方法示例
    void doSomething() {
        std::cout << "Doing something in thread: " 
                  << std::this_thread::get_id() << std::endl;
    }
};

// 静态成员定义
std::unique_ptr<ThreadSafeSingleton> ThreadSafeSingleton::instance_ = nullptr;
std::once_flag ThreadSafeSingleton::once_flag_;
```

## 方法二：Meyer's Singleton（C++11及以后更推荐）

```cpp
class MeyerSingleton {
private:
    // 私有构造函数
    MeyerSingleton() {
        std::cout << "MeyerSingleton constructed in thread: " 
                  << std::this_thread::get_id() << std::endl;
    }

public:
    // 禁止拷贝构造和赋值操作
    MeyerSingleton(const MeyerSingleton&) = delete;
    MeyerSingleton& operator=(const MeyerSingleton&) = delete;

    // 获取单例实例 - 使用局部静态变量
    static MeyerSingleton& getInstance() {
        static MeyerSingleton instance;  // 线程安全的懒加载
        return instance;
    }

    // 业务方法示例
    void doSomething() {
        std::cout << "MeyerSingleton doing something in thread: " 
                  << std::this_thread::get_id() << std::endl;
    }
};
```

## 完整测试代码

```cpp
#include <chrono>

// 测试函数
void testThreadSafeSingleton(int threadId) {
    auto start = std::chrono::high_resolution_clock::now();

    // 多次获取实例，验证是否为同一个对象
    for (int i = 0; i < 3; ++i) {
        ThreadSafeSingleton* singleton = ThreadSafeSingleton::getInstance();
        singleton->doSomething();
        std::this_thread::sleep_for(std::chrono::milliseconds(10));
    }

    auto end = std::chrono::high_resolution_clock::now();
    auto duration = std::chrono::duration_cast<std::chrono::microseconds>(end - start);
    std::cout << "Thread " << threadId << " completed in " 
              << duration.count() << " microseconds" << std::endl;
}

void testMeyerSingleton(int threadId) {
    auto start = std::chrono::high_resolution_clock::now();

    for (int i = 0; i < 3; ++i) {
        MeyerSingleton& singleton = MeyerSingleton::getInstance();
        singleton.doSomething();
        std::this_thread::sleep_for(std::chrono::milliseconds(10));
    }

    auto end = std::chrono::high_resolution_clock::now();
    auto duration = std::chrono::duration_cast<std::chrono::microseconds>(end - start);
    std::cout << "Meyer Thread " << threadId << " completed in " 
              << duration.count() << " microseconds" << std::endl;
}

int main() {
    std::cout << "=== Testing std::call_once Singleton ===" << std::endl;

    // 创建多个线程同时访问单例
    std::vector<std::thread> threads;
    for (int i = 0; i < 5; ++i) {
        threads.emplace_back(testThreadSafeSingleton, i);
    }

    for (auto& t : threads) {
        t.join();
    }

    std::cout << "\n=== Testing Meyer's Singleton ===" << std::endl;

    threads.clear();
    for (int i = 0; i < 5; ++i) {
        threads.emplace_back(testMeyerSingleton, i);
    }
